const config = {
  "previewFeatures": [],
  "clientVersion": "7.7.0",
  "engineVersion": "75cbdc1eb7150937890ad5465d861175c6624711",
  "activeProvider": "postgresql",
  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n  output   = \"../generated/prisma\" // Required in v7\n}\n\n// organisationId\ndatasource db {\n  provider = \"postgresql\"\n  // Note: No 'url' here anymore\n}\n\n//\n// ─────────────────────────────────────────────\n// 1. ORGANISATION (MULTI-TENANT ROOT)\n// ─────────────────────────────────────────────\n//\n\nmodel Organisation {\n  id       String  @id @default(cuid())\n  name     String\n  slug     String  @unique\n  isActive Boolean @default(true) // 1. Added for SaaS management\n\n  logoUrl      String?\n  contactEmail String?\n  contactPhone String?\n  address      String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt // 2. Added for audit/syncing\n\n  // Core Relations\n  users   User[]\n  staff   Staff[]\n  clients Client[]\n  jobs    Job[]\n  prices  PriceList[]\n\n  // Resources & Inventory (Aligned with our Brainstorm)\n  materials Material[] // 3. Added Material link\n  services  Service[] // 4. Added Service link\n\n  stockItems     StockItem[]\n  stockMovements StockMovement[]\n  deliveries     Delivery[]\n  b2bPushes      B2BPush[]\n  auditLogs      AuditLog[]\n  outboxEvents   OutboxEvent[]\n  payments       Payment[]\n\n  @@index([name])\n  @@index([slug])\n  @@index([createdAt])\n  @@index([isActive]) // 5. Index for fast SaaS status checks\n}\n\n//\n// ─────────────────────────────────────────────\n// 2. AUTH / USERS / RBAC\n// ─────────────────────────────────────────────\n//\n\nmodel OutboxEvent {\n  id      String @id @default(cuid())\n  type    String\n  payload Json\n  orgId   String\n\n  organisation Organisation @relation(fields: [orgId], references: [id])\n\n  status OutboxStatus @default(PENDING)\n\n  attempts    Int       @default(0)\n  lastError   String?\n  processedAt DateTime?\n\n  // 🚀 The \"Smart Worker\" Field\n  // If an email fails (e.g., SMTP down), the worker sets this to \n  // +5 mins so it doesn't keep spamming the failing service.\n  nextAttemptAt DateTime? @default(now())\n\n  createdAt DateTime @default(now())\n\n  @@index([orgId])\n  @@index([status, nextAttemptAt]) // Updated: Worker only picks up events where nextAttemptAt <= Now\n}\n\nenum OutboxStatus {\n  PENDING\n  PROCESSING\n  COMPLETED\n  FAILED\n}\n\n// Enum for user roles across system\nenum UserRole {\n  ADMIN\n  STAFF\n  CUSTOMER\n}\n\nmodel User {\n  id           String       @id @default(cuid())\n  orgId        String\n  organisation Organisation @relation(fields: [orgId], references: [id])\n\n  email     String\n  name      String\n  avatarUrl String?\n  role      UserRole\n\n  // --- Passwordless Auth Fields ---\n  isActive    Boolean   @default(true)\n  lastLoginAt DateTime?\n\n  // This is used for Magic Link / OTP verification\n  // Usually short-lived and cleared after use\n  authThreshold DateTime?\n\n  staffProfile Staff?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([orgId, email])\n  @@index([email])\n  @@index([orgId, isActive])\n}\n\nmodel VerificationToken {\n  id         String   @id @default(cuid())\n  identifier String // Typically the email\n  token      String   @unique\n  expires    DateTime\n  orgId      String\n\n  @@unique([identifier, token])\n  @@index([expires]) // For cleanup workers\n}\n\n//\n// ─────────────────────────────────────────────\n// 3. STAFF\n// ─────────────────────────────────────────────\n//\n\nmodel Staff {\n  id    String @id @default(cuid())\n  orgId String\n\n  // Relation to identity\n  userId String @unique\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  // Professional-only fields\n  phone          String?\n  specialisation String? // e.g., \"Large Format\", \"Finishing\", \"Design\"\n  isActive       Boolean @default(true)\n\n  // 🚀 Production Addition: Efficiency Tracking\n  // Useful for reporting who finishes jobs fastest or handles the most volume\n  joinedAt   DateTime?\n  baseSalary Float? // Optional: for internal payroll tracking\n\n  organisation Organisation @relation(fields: [orgId], references: [id])\n  assignedJobs Job[]        @relation(\"StaffJobs\")\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([orgId])\n  @@index([orgId, isActive])\n  @@index([specialisation]) // Index for fast filtering when assigning jobs\n}\n\n//\n// ─────────────────────────────────────────────\n// 4. CLIENTS\n// ─────────────────────────────────────────────\n//\n\nenum ClientType {\n  PRIVATE\n  COMPANY\n}\n\nmodel Client {\n  id    String @id @default(cuid())\n  orgId String\n\n  organisation Organisation @relation(fields: [orgId], references: [id])\n\n  type        ClientType\n  name        String\n  companyName String?\n  email       String?\n  phone       String\n  location    String?\n\n  profilePictureUrl String?\n\n  // ─────────────────────────────────────────────\n  // Lightweight CRM state (cached projections)\n  // ─────────────────────────────────────────────\n  isNew         Boolean @default(true)\n  recentStaffId String?\n\n  lastJobId   String?\n  lastJobDate DateTime?\n\n  totalJobs Int @default(0)\n\n  mostPrintedServiceId String?\n\n  notes String?\n\n  // ─────────────────────────────────────────────\n  // Relations\n  // ─────────────────────────────────────────────\n  jobs Job[]\n\n  createdAt  DateTime   @default(now())\n  deliveries Delivery[]\n\n  // ─────────────────────────────────────────────\n  // INDEXING (SaaS + CRM performance layer)\n  // ─────────────────────────────────────────────\n  @@index([orgId])\n  @@index([orgId, phone])\n  @@index([orgId, name])\n  @@index([orgId, lastJobDate])\n  @@index([orgId, totalJobs])\n  @@index([orgId, isNew])\n  @@index([recentStaffId])\n  @@index([mostPrintedServiceId])\n  @@index([lastJobId])\n}\n\n//\n// ─────────────────────────────────────────────\n// 5. PRICE LIST\n// ─────────────────────────────────────────────\n//\n\nenum PriceItemType {\n  MATERIAL\n  SERVICE\n}\n\nenum ServiceUnit {\n  sqft\n  sqm\n  sqcm\n  inch\n  ft\n  yd\n  mm\n  cm\n  m\n  meter\n  pack\n  piece\n  roll\n  box\n  ream\n  bottle\n  liter\n  hour\n  PER_PAGE\n  PER_100\n  PER_SQ_METER\n  PER_SET\n  PER_YARD\n}\n\nmodel PriceList {\n  id           String       @id @default(cuid())\n  orgId        String\n  organisation Organisation @relation(fields: [orgId], references: [id])\n\n  displayName String // Customer-facing name\n  salePrice   Float // Retail price\n\n  // Contextual Categories pulled from the Price List's role\n  materialCategory MaterialCategory?\n  serviceCategory  ServiceCategory?\n\n  // The Recipe: Multiple services/price items can point to one Material\n  materialId String?\n  material   Material? @relation(fields: [materialId], references: [id], onDelete: SetNull)\n\n  serviceId String?\n  service   Service? @relation(fields: [serviceId], references: [id], onDelete: SetNull)\n\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Job Links\n  jobs         Job[]\n  jobVariables JobVariable[]\n\n  @@index([orgId, isActive])\n  @@index([materialId])\n  @@index([serviceId])\n  @@index([materialCategory])\n  @@index([serviceCategory])\n}\n\nenum MaterialCalculationType {\n  FLAT // Quantity only (e.g., 100 Business Card Blanks)\n  DIMENSIONAL // Width x Height x Quantity (e.g., Vinyl, Flex, Acrylic)\n  LINEAR // Length x Quantity (e.g., Binding coils, Framing timber)\n  VOLUMETRIC // Liters/Grams (e.g., Ink, Resin)\n}\n\nenum MaterialCategory {\n  MEDIA // Vinyl, Paper, Canvas, Fabric\n  RIGID // Foam board, Alucobond, Acrylic, Wood\n  CONSUMABLE // Ink, Toner, Glue, Laminate\n  FINISHING // Eyelets, Roll-up stands, Frames, Binding wires\n  HARDWARE // Spare parts, Blades\n}\n\nenum MaterialStatus {\n  ACTIVE\n  ARCHIVED // Discontinued by supplier\n  OUT_OF_STOCK // Temporarily unavailable\n}\n\nmodel Material {\n  id            String                  @id @default(cuid())\n  name          String // Internal/Technical name\n  calcType      MaterialCalculationType\n  unit          ServiceUnit\n  purchasePrice Float // Base cost per unit\n\n  // 1-to-1 link to physical stock\n  stockItemId String?    @unique\n  stockItem   StockItem? @relation(fields: [stockItemId], references: [id], onDelete: SetNull)\n\n  priceListItems PriceList[]\n  jobVariables   JobVariable[]\n  orgId          String\n  organisation   Organisation  @relation(fields: [orgId], references: [id])\n\n  @@unique([orgId, name])\n  @@index([name])\n}\n\nenum ServiceCalculationType {\n  FIXED // A one-time fee regardless of size (e.g., Design Fee, Setup Fee)\n  PER_UNIT // Charged per item (e.g., Eyelet punching, Lamination per sheet)\n  AREA_BASED // Labor depends on size (e.g., Installation labor per sqft, Weeding vinyl)\n  TIME_BASED // Charged per duration (e.g., Machine hourly rate, Consulting)\n}\n\nenum ServiceCategory {\n  DESIGN // Graphic design, Pre-press, Layout\n  PRINTING // Actual machine time (Digital, Offset, Large Format)\n  FINISHING // Cutting, Folding, Laminating, Eyeleting\n  INSTALLATION // Site visits, Mounting, Vehicle wrapping\n  LOGISTICS // Delivery, Packaging, Handling\n}\n\nmodel Service {\n  id        String                 @id @default(cuid())\n  name      String // Workshop/Operation name\n  calcType  ServiceCalculationType\n  basePrice Float // Standard rate for the effort\n\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n\n  priceListItems PriceList[]\n  jobVariables   JobVariable[]\n  orgId          String\n  organisation   Organisation  @relation(fields: [orgId], references: [id])\n\n  @@unique([orgId, name])\n}\n\n//\n// ─────────────────────────────────────────────\n// 6. STOCK\n// ─────────────────────────────────────────────\n//\n\nmodel StockItem {\n  id           String       @id @default(cuid())\n  orgId        String\n  organisation Organisation @relation(fields: [orgId], references: [id])\n\n  // Current Physical State\n  totalRemaining    Float @default(0)\n  lowStockThreshold Float @default(0)\n\n  // Link back to Material Definition\n  material       Material?\n  stockMovements StockMovement[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([orgId])\n  @@index([totalRemaining]) // Fast filtering for out-of-stock\n}\n\nmodel StockMovement {\n  id           String       @id @default(cuid())\n  orgId        String\n  organisation Organisation @relation(fields: [orgId], references: [id])\n\n  stockItemId String\n  stockItem   StockItem @relation(fields: [stockItemId], references: [id], onDelete: Cascade)\n\n  type     StockMovementType\n  quantity Float // Amount added/removed\n\n  // Context: Why did this move?\n  referenceId   String? // JobID or JobVariableID\n  referenceType String? // \"JOB\" or \"JOB_VARIABLE\"\n\n  note      String?\n  createdBy String // User ID\n  createdAt DateTime @default(now())\n\n  @@index([orgId])\n  @@index([stockItemId, createdAt(sort: Desc)]) // Fast history lookup\n  @@index([referenceId])\n}\n\nenum StockMovementType {\n  RESTOCK\n  DEDUCT\n  WASTE\n  ADJUST\n}\n\nenum JobStatus {\n  PENDING\n  IN_PROGRESS\n  QUALITY_CHECK\n  READY_FOR_PICKUP\n  COMPLETED\n  CANCELLED\n  PAUSED\n}\n\nenum PaymentStatus {\n  UNPAID\n  PARTIAL\n  PAID\n}\n\nmodel Job {\n  id           String       @id @default(cuid())\n  orgId        String\n  organisation Organisation @relation(fields: [orgId], references: [id])\n\n  clientId String\n  client   Client @relation(fields: [clientId], references: [id])\n\n  // --- Core Reference ---\n  priceListId String\n  priceList   PriceList @relation(fields: [priceListId], references: [id])\n\n  // We keep serviceName as a snapshot of PriceList.displayName \n  // so the invoice doesn't change if you rename the PriceList item later.\n  serviceName String\n\n  // --- Multi-Service Support ---\n  variables JobVariable[]\n\n  // --- Dimensions & Quantity ---\n  quantity Float\n  width    Float?\n  height   Float?\n  unit     ServiceUnit? // Pulled from the linked Material\n\n  // --- Financial Snapshots (Critical for Production) ---\n  basePrice     Float // Snapshot of PriceList.salePrice at time of order\n  variableTotal Float @default(0)\n  totalPrice    Float // (basePrice * quantity/area) + variableTotal\n\n  costPrice    Float? // Sum of Material.purchasePrice * usage\n  profitMargin Float? // totalPrice - costPrice\n\n  // --- Payment & Status ---\n  paymentStatus PaymentStatus @default(UNPAID)\n  isPaid        Boolean       @default(false)\n  status        JobStatus     @default(PENDING)\n\n  // --- Relations ---\n  assignedStaffId String?\n  assignedStaff   Staff?  @relation(\"StaffJobs\", fields: [assignedStaffId], references: [id])\n\n  deliveries   Delivery[]\n  payments     Payment[]\n  b2bPushId    String?\n  b2bPush      B2BPush?   @relation(\"B2BPushResult\", fields: [b2bPushId], references: [id])\n  b2bSourceFor B2BPush[]  @relation(\"B2BOriginalSource\")\n\n  // --- Meta ---\n  notes       String?\n  completedAt DateTime?\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n\n  @@index([orgId, status])\n  @@index([orgId, paymentStatus])\n  @@index([clientId])\n  @@index([priceListId])\n  @@index([createdAt(sort: Desc)])\n}\n\nmodel JobVariable {\n  id    String @id @default(cuid())\n  jobId String\n  job   Job    @relation(fields: [jobId], references: [id], onDelete: Cascade)\n\n  priceListId String\n  priceList   PriceList @relation(fields: [priceListId], references: [id])\n\n  // --- 🚀 Critical Update: Dimensions for Variables ---\n  // This allows \"Finishing\" services like lamination to calculate area\n  quantity Float\n  width    Float?\n  height   Float?\n\n  unitPrice Float\n  subtotal  Float\n\n  // Relations to definitions for technical tracking\n  material   Material? @relation(fields: [materialId], references: [id])\n  materialId String?\n  service    Service?  @relation(fields: [serviceId], references: [id])\n  serviceId  String?\n\n  orgId     String\n  createdAt DateTime @default(now())\n\n  @@index([orgId, jobId])\n  @@index([jobId])\n  @@index([priceListId])\n}\n\n//\n// ─────────────────────────────────────────────\n// 8. DELIVERY\n// ─────────────────────────────────────────────\n//\nenum DeliveryType {\n  PHYSICAL_PICKUP\n  PRINTER_DELIVERY\n  CLIENT_COURIER\n}\n\nenum DeliveryStatus {\n  PENDING\n  SCHEDULED\n  OUT_FOR_DELIVERY\n  DELIVERED\n  PAUSED\n  FAILED\n}\n\nmodel Delivery {\n  id    String @id @default(cuid())\n  orgId String\n\n  organisation Organisation @relation(fields: [orgId], references: [id])\n\n  // ─────────────────────────────────────────────\n  // RELATIONS (domain integrity)\n  // ─────────────────────────────────────────────\n  jobId String\n  job   Job    @relation(fields: [jobId], references: [id])\n\n  clientId String\n  client   Client @relation(fields: [clientId], references: [id])\n\n  // ─────────────────────────────────────────────\n  // DELIVERY CORE\n  // ─────────────────────────────────────────────\n  type   DeliveryType\n  status DeliveryStatus @default(PENDING)\n\n  scheduledDate DateTime?\n  deliveredAt   DateTime?\n\n  handledBy String?\n  address   String?\n  notes     String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // ─────────────────────────────────────────────\n  // INDEXES (dispatch + logistics performance)\n  // ─────────────────────────────────────────────\n  @@index([orgId])\n  @@index([orgId, status])\n  @@index([orgId, jobId])\n  @@index([orgId, clientId])\n  @@index([scheduledDate])\n  @@index([status])\n}\n\n//\n// ─────────────────────────────────────────────\n// 9. PAYMENTS\n// ─────────────────────────────────────────────\n//\n\nenum PaymentMethod {\n  CASH\n  MOMO\n  BANK_TRANSFER\n  CARD\n  OTHER\n}\n\nmodel Payment {\n  id    String @id @default(cuid())\n  orgId String\n\n  organisation Organisation @relation(fields: [orgId], references: [id])\n\n  // ─────────────────────────────────────────────\n  // RELATION (financial integrity)\n  // ─────────────────────────────────────────────\n  jobId String\n  job   Job    @relation(fields: [jobId], references: [id])\n\n  // ─────────────────────────────────────────────\n  // PAYMENT CORE\n  // ─────────────────────────────────────────────\n  amount    Float\n  method    PaymentMethod\n  reference String?\n\n  screenshotUrl String?\n\n  confirmedBy String?\n  confirmedAt DateTime @default(now())\n\n  createdAt DateTime @default(now())\n\n  // ─────────────────────────────────────────────\n  // INDEXES (finance + reporting performance)\n  // ─────────────────────────────────────────────\n  @@index([orgId])\n  @@index([orgId, jobId])\n  @@index([orgId, method])\n  @@index([orgId, confirmedAt])\n  @@index([reference])\n}\n\n//\n// ─────────────────────────────────────────────\n// 10. B2B LAYER\n// ─────────────────────────────────────────────\n//\nenum B2BStatus {\n  PENDING\n  ACCEPTED\n  NEGOTIATING\n  REJECTED\n  COMPLETED\n}\n\nmodel B2BPush {\n  id    String @id @default(cuid())\n  orgId String\n\n  organisation Organisation @relation(fields: [orgId], references: [id])\n\n  // ─────────────────────────────────────────────\n  // RELATION (critical fix)\n  // ─────────────────────────────────────────────\n  originalJobId String\n  originalJob   Job    @relation(\"B2BOriginalSource\", fields: [originalJobId], references: [id])\n\n  jobs Job[] @relation(\"B2BPushResult\")\n\n  // ─────────────────────────────────────────────\n  // BUSINESS SNAPSHOT DATA\n  // ─────────────────────────────────────────────\n  clientName  String\n  serviceName String\n  specs       String\n  deadline    DateTime\n\n  suggestedPrice Float?\n\n  // ─────────────────────────────────────────────\n  // WORKFLOW STATE\n  // ─────────────────────────────────────────────\n  status B2BStatus @default(PENDING)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // ─────────────────────────────────────────────\n  // INDEXES (workflow + urgency optimization)\n  // ─────────────────────────────────────────────\n  @@index([orgId])\n  @@index([orgId, status])\n  @@index([orgId, originalJobId])\n  @@index([deadline])\n}\n\nmodel AuditLog {\n  id    String @id @default(cuid())\n  orgId String\n\n  organisation Organisation @relation(fields: [orgId], references: [id])\n\n  // ─────────────────────────────────────────────\n  // EVENT DATA\n  // ─────────────────────────────────────────────\n  action     String\n  entityId   String\n  entityType String\n\n  performedBy String\n\n  meta Json?\n\n  timestamp DateTime @default(now())\n\n  // ─────────────────────────────────────────────\n  // INDEXES (debug + analytics + compliance)\n  // ─────────────────────────────────────────────\n  @@index([orgId])\n  @@index([orgId, entityType])\n  @@index([orgId, entityId])\n  @@index([timestamp(sort: Desc)])\n}\n"
}

